import numpy as np
from scipy import stats

def task_func(df):
    # Initialize p-values and test results dictionaries
    p_values = {}
    test_results = {}

    # Perform Shapiro-Wilk test on each column of the DataFrame
    for col in df.columns:
        result, p = stats.shapiro(df[col])
        p_values[col] = p
        test_results[col] = p > 0.05

    # Return the p-values and test results dictionaries
    return (p_values, test_results)
